	"github.com/spf13/viper"
)

const versionTemplate = `DDx {{.Version}}
Commit: {{index .Annotations "commit"}}
Built: {{index .Annotations "date"}}
`

// CommandFactory creates fresh command instances without global state
type CommandFactory struct {
	// Configuration options
	Version string
	Commit  string
	Date    string

	// Working directory (injected once at startup)
	WorkingDir string

	// AgentRunnerOverride overrides the agent runner used by the
	// execute-bead path (legacy agent.AgentRunner interface). For testing.
	AgentRunnerOverride agent.AgentRunner

	// ExecAgentRunnerOverride overrides the agent runner used by execStore.
	// SD-024 Stage 2: distinct from AgentRunnerOverride because the exec
	// AgentRunner interface has migrated to (ctx, ResolvedConfig, runtime),
	// while agent.AgentRunner still uses the legacy RunArgs signature.
	// For testing.
	ExecAgentRunnerOverride ddxexec.AgentRunner

	// executeBeadGitOverride overrides git operations in execute-bead worker (for testing).
	executeBeadGitOverride agent.GitOps

	// executeBeadOrchestratorGitOverride overrides git operations in the
	// execute-bead orchestrator (LandBeadResult) for testing.
	executeBeadOrchestratorGitOverride agent.OrchestratorGitOps

	// executeBeadLandingGitOverride overrides the LandingGitOps used by the
	// single-bead CLI and the queue-work LandCoordinator for testing.
	executeBeadLandingGitOverride agent.LandingGitOps

	// executeBeadLandingAdvancerOverride, when non-nil, replaces the default
	// Land() wrapper used by the interactive single-bead CLI with a custom
	// callback. Tests inject this to assert on the number of land calls
	// without needing a real git repo.
	executeBeadLandingAdvancerOverride func(res *agent.ExecuteBeadResult) (*agent.LandResult, error)

	// syncGitRunnerOverride replaces the real git runner in 'ddx sync' (for testing).
	syncGitRunnerOverride syncGitRunner

	// tryExecutorOverride, when non-nil, replaces the real executor used by
	// "ddx try". Injected by tests to observe claim/execute/outcome without
	// shelling out to a real agent harness.
	tryExecutorOverride agent.ExecuteBeadExecutor

	// resourceCheckerOverride, when non-nil, replaces the default execution
	// resource preflight used by ddx try and ddx work.
	resourceCheckerOverride agent.ExecutionResourceChecker

	// Custom viper instance for isolation
	viperInstance *viper.Viper

	// Update checker instance (stores check result for PostRunE)
	updateChecker *update.Checker
	updateDone    chan struct{}
	updateMu      sync.Mutex
}

// NewCommandFactory creates a new command factory with default settings
func NewCommandFactory(workingDir string) *CommandFactory {
	return &CommandFactory{
		Version:       Version,
		Commit:        Commit,
		Date:          Date,
		WorkingDir:    workingDir,
		viperInstance: viper.New(),
	}
}

// NewRootCommand creates a fresh root command with all subcommands
func (f *CommandFactory) NewRootCommand() *cobra.Command {
	// Local flag variables scoped to this command instance
	var cfgFile string
	var verbose bool
	var libraryPath string

	// Create fresh root command
	rootCmd := &cobra.Command{
		Use:   "ddx",
		Short: "Document-Driven Development eXperience - AI development toolkit",
		Long: color.New(color.FgCyan).Sprint(banner) + `
DDx is a toolkit for AI-assisted development that helps you:

• Share templates, prompts, and patterns across projects
• Maintain consistent development practices
• Integrate AI tooling seamlessly
• Contribute improvements back to the community

Get started:
  ddx init          Initialize DDx in your project
  ddx list          See available resources
  ddx doctor        Check installation and diagnose issues
  ddx cleanup       Inspect and clean stale DDx execution resources

More information:
  Documentation: https://github.com/DocumentDrivenDX/ddx
  Issues & Support: https://github.com/DocumentDrivenDX/ddx/issues`,
		PersistentPreRun: func(cmd *cobra.Command, args []string) {
			if verbose {
				fmt.Printf("DDx %s (commit: %s, built: %s)\n", f.Version, f.Commit, f.Date)
			}
		},
	}

	rootCmd.Version = formattedVersion(f.Version)
	rootCmd.Annotations = map[string]string{
		"commit": f.Commit,
		"date":   f.Date,
	}
	rootCmd.SetVersionTemplate(versionTemplate)

	// Setup flags - these are now local to this command instance
	rootCmd.PersistentFlags().StringVar(&cfgFile, "config", "", "config file (default is $HOME/.ddx.yml)")
	rootCmd.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "verbose output")
	rootCmd.PersistentFlags().StringVar(&libraryPath, "library-base-path", "", "override path for DDx library location")

	// Store flag values in command context for access by subcommands
	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
		// Initialize config with the local viper instance
		f.initConfig(cfgFile, libraryPath)

		// Version gate: block old binary from running in newer project
		if err := f.checkVersionGate(cmd); err != nil {
			return err
		}

		// Check for updates (synchronous, once per 24h)
		f.checkForUpdates(cmd)

		// Call the original PersistentPreRun if it exists
		if rootCmd.PersistentPreRun != nil {
			rootCmd.PersistentPreRun(cmd, args)
		}
		return nil
	}

	// Display update notification and staleness hints after command completes
	rootCmd.PersistentPostRunE = func(cmd *cobra.Command, args []string) error {
		if err := f.displayUpdateNotification(cmd); err != nil {
			return err
		}
		f.displayStalenessHints(cmd)
		return nil
	}

	// Add all subcommands
	f.registerSubcommands(rootCmd)

	// Keep the persona APIs in the static production graph. Cobra dispatch
	// does not always show up in deadcode RTA, so this explicit hook keeps the
	// real CLI implementations visible without changing runtime behavior.
	persona.KeepReachabilityForDeadcode()
	metaprompt.KeepReachabilityForDeadcode()
	metric.KeepReachabilityForDeadcode()

	return rootCmd
}

func formattedVersion(version string) string {
	if version == "dev" {
		return "v0.0.1-dev"
	}
	if !strings.HasPrefix(version, "v") {
		return "v" + version
	}
	return version
}

func (f *CommandFactory) versionOutput() string {
	return fmt.Sprintf("DDx %s\nCommit: %s\nBuilt: %s\n", formattedVersion(f.Version), f.Commit, f.Date)
}

// initConfig initializes configuration for this command instance
func (f *CommandFactory) initConfig(cfgFile, libPath string) {
	// Store library path override if provided
	if libPath != "" {
		_ = os.Setenv("DDX_LIBRARY_BASE_PATH", libPath)
	}

	if cfgFile != "" {
		// Use config file from the flag
		f.viperInstance.SetConfigFile(cfgFile)
	} else {
		// Find home directory
		home, err := os.UserHomeDir()
		if err == nil {
			// Search for config in home directory with name ".ddx" (without extension)
			f.viperInstance.AddConfigPath(home)
			f.viperInstance.AddConfigPath(".")
			f.viperInstance.SetConfigType("yaml")
			f.viperInstance.SetConfigName(".ddx")
		}
	}

	f.viperInstance.AutomaticEnv() // read in environment variables that match

	// If a config file is found, read it in
	if err := f.viperInstance.ReadInConfig(); err == nil {
		if verbose := f.viperInstance.GetBool("verbose"); verbose {
			_, _ = fmt.Fprintln(os.Stderr, "Using config file:", f.viperInstance.ConfigFileUsed())
		}
	}
}

// checkForUpdates performs automatic update check (synchronous, once per 24h)
func (f *CommandFactory) checkForUpdates(cmd *cobra.Command) {
	// Check if disabled via env var
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		return
	}

	// Load config
	cfg, err := config.Load()
	if err != nil {
		// Silent failure - use defaults
		cfg = config.DefaultNewConfig()
	}

	// Check if disabled via config
	if cfg.UpdateCheck != nil && !cfg.UpdateCheck.Enabled {
		return
	}

	// Create checker and perform check (synchronous)
	checker := update.NewChecker(f.Version, cfg)
	f.updateMu.Lock()
	f.updateChecker = checker
	f.updateDone = make(chan struct{})
	done := f.updateDone

}

// Create library directory structure (offline-safe — plugin install may fail).
libraryPath := filepath.Join(workingDir, localConfig.Library.Path)
for _, sub := range []string{"prompts", "personas", "patterns", "templates", "configs"} {
	_ = os.MkdirAll(filepath.Join(libraryPath, sub), 0755)
}

// Create .ddx/skills/ in project for bootstrap skills
projectSkillsDir := filepath.Join(workingDir, ".ddx", "skills")
if err := os.MkdirAll(projectSkillsDir, 0755); err != nil {
	_, _ = fmt.Fprintf(os.Stderr, "Warning: could not create .ddx/skills directory: %v\n", err)
}

// Copy bootstrap skills to .ddx/skills/, .agents/skills/, and .claude/skills/
// All as real files (not symlinks) so they're git-trackable.
// Stale pre-consolidation ddx-* skill dirs (ddx-bead, ddx-run, etc.) are
// removed first so harnesses don't see drifted skills.
bootstrapSkillNames := []string{"ddx"}
for _, dir := range []string{
	filepath.Join(workingDir, ".ddx", "skills"),
	filepath.Join(workingDir, ".agents", "skills"),
	filepath.Join(workingDir, ".claude", "skills"),
} {
	_ = os.MkdirAll(dir, 0755)
	cleanupBootstrapSkills(dir, bootstrapSkillNames)
}
// .agents/skills/ + .claude/skills/ via shared installer.
if err := skills.Install(skills.SkillFiles, workingDir, skills.Options{Force: opts.Force}); err != nil {
	_, _ = fmt.Fprintf(os.Stderr, "Warning: skill install failed: %v\n", err)
}
// .ddx/skills/ stays bootstrap-only (plugin skills do NOT register here).
registerBootstrapDDxSkills(workingDir, opts.Force)

// Auto-install the default ddx plugin (library resources).
// Non-fatal: if offline or install fails, warn and continue.
reg := registry.BuiltinRegistry()
if pkg, err := reg.Find("ddx"); err == nil {
	var oldFiles []string
	if state, _ := registry.LoadState(); state != nil {
		if old := state.FindInstalled(pkg.Name); old != nil {
			oldFiles = append([]string{}, old.Files...)
		}
	}

	if entry, installErr := registry.InstallPackage(pkg, workingDir); installErr != nil {
		_, _ = fmt.Fprintf(os.Stderr, "Warning: could not install default library: %v\n", installErr)
	} else {
		_ = removeStaleFilesFromInstall(oldFiles, entry.Files)

		state, _ := registry.LoadState()
		if state == nil {
			state = &registry.InstalledState{}
		}
		state.AddOrUpdate(entry)
		_ = registry.SaveState(state)
	}
}

// Write .ddx/versions.yaml (system-managed, tracks binary version)
writeProjectVersions(workingDir, opts.DDxVersion)

if !opts.NoGit {
	// Inject initial meta-prompt if the prompt file actually exists (unless explicitly skipped)
	if !opts.SkipClaudeInjection {
		if err := injectInitialMetaPrompt(localConfig, workingDir); err != nil {
			// Don't fail - meta-prompt is optional enhancement
			// Only warn if the specific prompt file exists but has issues
			promptPath := localConfig.GetMetaPrompt()
			if promptPath != "" {
				fullPromptPath := filepath.Join(workingDir, localConfig.Library.Path, promptPath)
				if _, statErr := os.Stat(fullPromptPath); statErr == nil {
					_, _ = fmt.Fprintf(os.Stderr, "Warning: Failed to inject meta-prompt: %v\n", err)
				}
			}
		}
	}

	// Generate AGENTS.md with guidance for AI agents working in this repo.
	generateAgentsMD(workingDir)

	// Commit config and versions files
	ctx := context.Background()
	gitAdd := gitpkg.Command(ctx, workingDir, "add", ".ddx/config.yaml", ".ddx/versions.yaml", "AGENTS.md", ".gitignore")
	if err := gitAdd.Run(); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to stage config file: %v", err))
	}

	gitCommit := gitpkg.Command(ctx, workingDir, "commit", "-m", "chore: add DDx configuration")
	if err := gitCommit.Run(); err != nil {
		return nil, NewExitError(1, fmt.Sprintf("Failed to commit config file: %v", err))
	}

	// Enable per-worktree git config so that `git config --local` inside
	// linked worktrees (e.g. execute-bead worktrees) writes to a
	// worktree-specific file rather than the shared .git/config. This
	// prevents agents from accidentally corrupting repo-level settings like
	// core.bare when running in an isolated worktree.
	gitWorktreeCfg := gitpkg.Command(ctx, workingDir, "config", "extensions.worktreeConfig", "true")
	_ = gitWorktreeCfg.Run() // best-effort; older git versions may not support it
}

package registry

import (
	"fmt"
	"strings"
)

// PackageType represents the type of a registry package.
type PackageType string

const (
	PackageTypeWorkflow     PackageType = "workflow"
	PackageTypePlugin       PackageType = "plugin"
	PackageTypePersonaPack  PackageType = "persona-pack"
	PackageTypeTemplatePack PackageType = "template-pack"
	PackageTypeResource     PackageType = "resource"
)

// InstallMapping describes a source→target copy during installation.
type InstallMapping struct {
	Source string `yaml:"source"`
	Target string `yaml:"target"`
}

// PackageInstall describes what to copy during installation.
type PackageInstall struct {
	Root       *InstallMapping  `yaml:"root,omitempty"`       // plugin root (e.g., .ddx/plugins/helix)
	Skills     []InstallMapping `yaml:"skills,omitempty"`     // skills directories (copied to each target)
	Scripts    *InstallMapping  `yaml:"scripts,omitempty"`    // scripts/binaries
	Symlinks   []SymlinkMapping `yaml:"symlinks,omitempty"`   // post-install symlinks
	Executable []string         `yaml:"executable,omitempty"` // paths (relative to root) that must be executable
}

// SymlinkMapping describes a symlink to create during installation.
type SymlinkMapping struct {
	Source string `yaml:"source"` // the source path (relative to install root)
	Target string `yaml:"target"` // the target path (where symlink points)
}

// Package describes a single installable package.
type Package struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        PackageType    `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  string         `yaml:"api_version,omitempty"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords,omitempty"`
	// Extra captures top-level keys not recognized by this DDx version so
	// newer manifests can keep their unknown fields in memory without
	// silently dropping them. See SD-018 "Manifest Versioning". Not
	// marshaled via `yaml:"-"` so callers must preserve it explicitly.
	Extra map[string]any `yaml:"-"`
}

// Registry holds the list of known packages.
type Registry struct {
	Packages []Package
}

// BuiltinRegistry returns the built-in registry of known packages.
func BuiltinRegistry() *Registry {
	return &Registry{
		Packages: []Package{
			{
				Name:        "ddx",
				Version:     "0.4.7",
				Description: "DDx default library: prompts, personas, MCP configs, environments, skills",
				Type:        PackageTypePlugin,
				Source:      "https://github.com/DocumentDrivenDX/ddx",
				Install: PackageInstall{
					Root: &InstallMapping{
						Source: "library",
						Target: ".ddx/plugins/ddx",
					},
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
				},
				Keywords: []string{"library", "prompts", "personas", "mcp", "default", "skills"},
			},
			{
				Name:        "helix",
				Version:     "0.3.2",
				Description: "Supervisory autopilot for AI-assisted software delivery",
				Type:        PackageTypeWorkflow,
				Source:      "https://github.com/DocumentDrivenDX/helix",
				Install: PackageInstall{
					// Plugin installs are project-local (FEAT-015): the tree
					// lives under .ddx/plugins/<name>/, never in $HOME.
					Root: &InstallMapping{
						Source: ".",
						Target: ".ddx/plugins/helix",
					},
					// Skills installed to project-local skill directories.
					// skills.Install copies real files into both .agents/skills/
					// and .claude/skills/ regardless of mapping target.
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
					// CLI script → ~/.local/bin/helix
					// Uses scripts/helix directly (bin/helix has a symlink
					// resolution bug when invoked through a symlink).
					Scripts: &InstallMapping{
						Source: "scripts/helix",
						Target: "~/.local/bin/helix",
					},
					Executable: []string{
						"scripts/helix",
					},
				},
				Keywords: []string{"workflow", "methodology", "ai", "development"},
			},
		},
	}
}

// Find returns the package with the given name, or an error if not found.
func (r *Registry) Find(name string) (*Package, error) {
	for i := range r.Packages {
		if r.Packages[i].Name == name {
			return &r.Packages[i], nil
		}
	}
	return nil, fmt.Errorf("package %q not found in registry", name)
}

// Search returns all packages whose name, description, or keywords contain the query.
func (r *Registry) Search(query string) []Package {
	q := strings.ToLower(query)
	var results []Package
	for _, pkg := range r.Packages {
		if matchesQuery(pkg, q) {
			results = append(results, pkg)
		}
	}
	return results
}

func matchesQuery(pkg Package, query string) bool {
	if strings.Contains(strings.ToLower(pkg.Name), query) {
		return true
	}
	if strings.Contains(strings.ToLower(pkg.Description), query) {
		return true
	}
	if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
		return true
	}
	for _, kw := range pkg.Keywords {
		if strings.Contains(strings.ToLower(kw), query) {
			return true
		}
	}
	return false
}

// IsResourcePath returns true if name looks like a resource path (e.g. "persona/foo").
func IsResourcePath(name string) bool {
	return strings.Contains(name, "/")
}

package registry

import (
	"archive/tar"
	"compress/gzip"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/skills"
)

// InstallPackage downloads the source release tarball and copies declared install mappings
// into projectRoot. It records installed files (project-relative when possible) in the
// returned InstalledEntry.
func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	// FEAT-015 early validation: if the package argument already declares a
	// home-rooted Root.Target, reject it before doing any I/O. The post-
	// manifest check below covers manifest-supplied targets after download.
	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	// Switch into projectRoot so relative install targets resolve against the
	// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
	// the recorded entry.Files paths project-relative.
	if projectRoot != "" {
		absProject, absErr := filepath.Abs(projectRoot)
		if absErr == nil {
			if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
				if err := os.Chdir(absProject); err == nil {
					defer func() { _ = os.Chdir(origDir) }()
				}
			}
		}
	}

	// Download and extract the release tarball to a temp directory.
	tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}

	if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(extractedDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
		if manifestPkg != nil {
			pkg = manifestPkg
		}
	} else {
		if len(manifestIssues) > 0 {
			return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
		}
		return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &InstallMapping{
			Source: ".",
			Target: defaultPackageRootTarget(pkg.Name),
		}
	}

	// FEAT-015: plugin install targets must be project-relative. Manifests
	// that try to write into the user's home are rejected so plugins can't
	// pollute global state.
	if strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	if issues := ValidatePackageStructure(extractedDir, pkg); len(issues) > 0 {
		return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
	}

	// Process Root mapping — copy the plugin tree into the project-local
	// install location (e.g. .ddx/plugins/<name>/).
	var installedRoot string
	files, err := copyMapping(extractedDir, pkg.Install.Root)
	if err != nil {
		return entry, fmt.Errorf("installing plugin root: %w", err)
	}
	entry.Files = append(entry.Files, files...)
	installedRoot = ExpandHome(pkg.Install.Root.Target)

	// Ensure declared executables have the execute bit set.
	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(installedRoot, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	// Process Skills via the shared installer. skills.Install copies real
	// files into <projectRoot>/.agents/skills/ and <projectRoot>/.claude/skills/.
	// No symlinks are ever created — this is the cross-platform invariant
	// that FEAT-015 relies on.
	if len(pkg.Install.Skills) > 0 {
		// Use the extracted tarball as the skill source rather than the
		// post-copy installed root: copyMapping skips broken symlinks (a
		// known GitHub-tarball quirk), so the installed tree may have an
		// empty .agents/skills/. The extracted dir preserves the original
		// layout — including broken symlinks — and skills.discoverSkills
		// recovers them via the skills/<name> fallback.
		absExtracted, absErr := filepath.Abs(extractedDir)
		if absErr != nil {
			absExtracted = extractedDir
		}
		absProject, absErr := filepath.Abs(".")
		if absErr != nil {
			absProject = projectRoot
		}
		if err := skills.Install(os.DirFS(absExtracted), absProject, skills.Options{Force: true}); err != nil {
			return entry, fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, recordInstalledSkills(absExtracted, absProject)...)
	}

	// Process Scripts mapping — copy the script to the target path.
	// If the target is already a symlink, the developer is managing it
	// themselves (e.g. symlink to their git checkout) — skip with a notice.
	if pkg.Install.Scripts != nil {
		dst := ExpandHome(pkg.Install.Scripts.Target)
		if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			srcDir := extractedDir
			if installedRoot != "" {
				srcDir = installedRoot
			}
			files, err := copyMapping(srcDir, pkg.Install.Scripts)
			if err != nil {
				return entry, fmt.Errorf("installing scripts: %w", err)
			}
			entry.Files = append(entry.Files, files...)

			// Ensure the installed script is executable.
			if info, err := os.Stat(dst); err == nil && !info.IsDir() {
				_ = os.Chmod(dst, info.Mode()|0111)
			}
		}
	}

	// Process symlinks.
	for _, sym := range pkg.Install.Symlinks {
		src := ExpandHome(sym.Source)
		dst := ExpandHome(sym.Target)

		// Create parent dir if needed.
		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
			return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
		}

		// Remove existing symlink/file if present.
		if _, err := os.Lstat(dst); err == nil {
			if err := os.RemoveAll(dst); err != nil {
				return entry, fmt.Errorf("removing existing %s: %w", dst, err)
			}
		}

		if err := os.Symlink(src, dst); err != nil {
			return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
		}
		entry.Files = append(entry.Files, dst)
	}

	return entry, nil
}

// recordInstalledSkills returns project-relative paths to the skill directories
// installed under .agents/skills/ and .claude/skills/ that came from the given
// plugin root.
func recordInstalledSkills(installedRoot, projectRoot string) []string {
	var names []string
	for _, candidate := range []string{
		filepath.Join(installedRoot, ".agents", "skills"),
		filepath.Join(installedRoot, "skills"),
	} {
		entries, err := os.ReadDir(candidate)
		if err != nil {
			continue
		}
		for _, e := range entries {
			if e.IsDir() || e.Type()&os.ModeSymlink != 0 {
				names = append(names, e.Name())
			}
		}
		if len(names) > 0 {
			break
		}
	}

	var files []string
	for _, name := range names {
		for _, sub := range []string{".agents/skills", ".claude/skills"} {
			rel := filepath.Join(filepath.FromSlash(sub), name)
			files = append(files, rel)
		}
	}
	return files
}

